21.         // GET: Students - Admins and Teachers can view
22.         public ActionResult Index(string sortOrder, string currentFilter, string searchString, int? page)
23.         {
24.             ViewBag.CurrentSort = sortOrder;
25.             ViewBag.NameSortParm = String.IsNullOrEmpty(sortOrder) ? "name_desc" : "";
26.             ViewBag.DateSortParm = sortOrder == "Date" ? "date_desc" : "Date";
27. 
28.             if (searchString != null)
29.             {
30.                 page = 1;
31.             }
32.             else
33.             {
34.                 searchString = currentFilter;
35.             }
36. 
37.             ViewBag.CurrentFilter = searchString;
38. 
39.             var students = from s in db.Students
40.                            select s;
41. 
42.             if (!String.IsNullOrEmpty(searchString))
43.             {
44.                 students = students.Where(s => s.LastName.Contains(searchString)
45.                                        || s.FirstMidName.Contains(searchString));
46.             }
47. 
48.             switch (sortOrder)
49.             {
50.                 case "name_desc":
51.                     students = students.OrderByDescending(s => s.LastName);
52.                     break;
53.                 case "Date":
54.                     students = students.OrderBy(s => s.EnrollmentDate);
55.                     break;
56.                 case "date_desc":
57.                     students = students.OrderByDescending(s => s.EnrollmentDate);
58.                     break;
59.                 default:
60.                     students = students.OrderBy(s => s.LastName);
61.                     break;
62.             }
63. 
64.             int pageSize = 10;
65.             int pageNumber = (page ?? 1);
66.             return View(PaginatedList<Student>.Create(students, pageNumber, pageSize));
67.         }
68. 
69.         // GET: Students/Details/5 - Admins and Teachers can view details
70.         public ActionResult Details(int? id)
71.         {
72.             if (id == null)
73.             {
74.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
75.             }
76.             Student student = db.Students
77.                 .Include(s => s.Enrollments)
78.                     .ThenInclude(e => e.Course)
79.                 .Where(s => s.ID == id).Single();
80.             if (student == null)
81.             {
82.                 return NotFound();
83.             }
84.             return View(student);
85.         }
