public class CoursesController : BaseController
{
    private readonly IWebHostEnvironment _env;
    private readonly ILogger<CoursesController> _logger;

    public CoursesController(SchoolContext context, IWebHostEnvironment env, ILogger<CoursesController> logger) : base(context) { _env = env; _logger = logger; }

    public ActionResult Index()
    {
        var courses = db.Courses.Include(c => c.Department);
        return View(courses.ToList());
    }

    public ActionResult Details(int? id)
    {
        if (id == null) return new StatusCodeResult(400);
        Course course = db.Courses.Include(c => c.Department).Where(c => c.CourseID == id).Single();
        if (course == null) return NotFound();
        return View(course);
    }

    public ActionResult Create()
    {
        ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name");
        return View(new Course());
    }

    [HttpPost] [ValidateAntiForgeryToken]
    public ActionResult Create([Bind(...)] Course course, IFormFile teachingMaterialImage)
    {
        if (ModelState.IsValid)
        {
            // File upload validation (extension, size <=5MB)
            // If file valid: saves file, sets TeachingMaterialImagePath
            // If file invalid: adds model error, returns View
            db.Courses.Add(course);
            db.SaveChanges();
            SendEntityNotification("Course", course.CourseID.ToString(), course.Title, EntityOperation.CREATE);
            return RedirectToAction("Index");
        }
        ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
        return View(course);
    }

    public ActionResult Edit(int? id)
    {
        if (id == null) return new StatusCodeResult(400);
        Course course = db.Courses.Find(id);
        if (course == null) return NotFound();
        ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
        return View(course);
    }

    [HttpPost] [ValidateAntiForgeryToken]
    public ActionResult Edit([Bind(...)] Course course, IFormFile teachingMaterialImage)
    {
        if (ModelState.IsValid)
        {
            // Similar file upload logic as Create, plus deletes old file if replacing
            db.Entry(course).State = EntityState.Modified;
            db.SaveChanges();
            SendEntityNotification("Course", course.CourseID.ToString(), course.Title, EntityOperation.UPDATE);
            return RedirectToAction("Index");
        }
        ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
        return View(course);
    }

    public ActionResult Delete(int? id)
    {
        if (id == null) return new StatusCodeResult(400);
        Course course = db.Courses.Include(c => c.Department).Where(c => c.CourseID == id).Single();
        if (course == null) return NotFound();
        return View(course);
    }

    [HttpPost, ActionName("Delete")] [ValidateAntiForgeryToken]
    public ActionResult DeleteConfirmed(int id)
    {
        Course course = db.Courses.Find(id);
        var courseTitle = course.Title;
        // Deletes image file if exists
        db.Courses.Remove(course);
        db.SaveChanges();
        SendEntityNotification("Course", id.ToString(), courseTitle, EntityOperation.DELETE);
        return RedirectToAction("Index");
    }
}
