using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_SetsTotalPages()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Theory]
        [InlineData(10, 3, 4)]   // 10 items / 3 per page = ceil(3.33) = 4
        [InlineData(10, 5, 2)]   // 10 items / 5 per page = 2
        [InlineData(1, 5, 1)]    // 1 item / 5 per page = 1
        [InlineData(0, 5, 0)]    // 0 items / 5 per page = 0
        [InlineData(7, 3, 3)]    // 7 items / 3 per page = ceil(2.33) = 3
        [InlineData(9, 3, 3)]    // 9 items / 3 per page = 3
        public void TotalPages_CalculatedCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_OnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);

            Assert.False(list.HasPreviousPage);
        }

        [Theory]
        [InlineData(2)]
        [InlineData(3)]
        [InlineData(4)]
        public void HasPreviousPage_ReturnsTrue_OnPageGreaterThan1(int pageIndex)
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, pageIndex, 3);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_OnLastPage()
        {
            // 10 items, 3 per page = 4 total pages
            var list = new PaginatedList<int>(new List<int> { 10 }, 10, 4, 3);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 5);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsFirstPageItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(new List<int> { 1, 2, 3 }, result.ToList());
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_ReturnsMiddlePageItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 3);

            Assert.Equal(new List<int> { 4, 5, 6 }, result.ToList());
            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_ReturnsLastPageItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 4, 3);

            Assert.Equal(new List<int> { 10 }, result.ToList());
            Assert.Equal(4, result.PageIndex);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_SingleItem_ReturnsCorrectly()
        {
            var source = new List<int> { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = new List<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.Equal(1, result.PageIndex);
        }

        [Fact]
        public void Create_CorrectTotalPages()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_ItemsAreInList()
        {
