using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain the static queue to avoid interference between tests
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_CreatesNotificationWithCorrectProperties()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.True(notification.CreatedAt <= DateTime.Now);
            Assert.True(notification.CreatedAt > DateTime.Now.AddSeconds(-5));
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student 'John Doe' has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student (ID: 42) has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Course", "101", (string)null!, EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Course (ID: 101) has been updated", notification!.Message);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsQueuedNotification()
        {
            _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "New Student 'Test' has been created")]
        [InlineData(EntityOperation.UPDATE, "Student 'Test' has been updated")]
        [InlineData(EntityOperation.DELETE, "Student 'Test' has been deleted")]
        public void SendNotification_GeneratesCorrectMessage_ForOperation(
            EntityOperation operation, string expectedMessage)
        {
            _service.SendNotification("Student", "1", "Test", operation);

            var notification = _service.ReceiveNotification();

            Assert.Equal(expectedMessage, notification!.Message);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "New Instructor (ID: 5) has been created")]
        [InlineData(EntityOperation.UPDATE, "Instructor (ID: 5) has been updated")]
        [InlineData(EntityOperation.DELETE, "Instructor (ID: 5) has been deleted")]
        public void SendNotification_WithoutDisplayName_GeneratesCorrectMessage_ForOperation(
            EntityOperation operation, string expectedMessage)
        {
            _service.SendNotification("Instructor", "5", operation);

            var notification = _service.ReceiveNotification();

            Assert.Equal(expectedMessage, notification!.Message);
        }

        [Fact]
        public void MultipleNotifications_ReceivedInOrder()
        {
            _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", "Third", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("Student", first!.EntityType);
            Assert.Equal("Course", second!.EntityType);
            Assert.Equal("Department", third!.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));

            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();

            var exception = Record.Exception(() => service.Dispose());

            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_SetsCorrectEntityType()
        {
            _service.SendNotification("Course", "101", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("101", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void SendNotification_OperationStoredAsString()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.Equal("UPDATE", notification!.Operation);
        }

        [Fact]
        public void SendNotification_IsRead_DefaultsFalse()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.False(notification!.IsRead);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "7", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student (ID: 7) has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "7", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student (ID: 7) has been created", notification!.Message);
        }
    }
}

