+
+            var result = PaginatedList<int>.Create(source, 2, 3);
+
+            Assert.Equal(new List<int> { 4, 5, 6 }, result.ToList());
+            Assert.Equal(2, result.PageIndex);
+        }
+
+        [Fact]
+        public void Create_ReturnsLastPageItems()
+        {
+            var source = Enumerable.Range(1, 10).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 4, 3);
+
+            Assert.Equal(new List<int> { 10 }, result.ToList());
+            Assert.Equal(4, result.PageIndex);
+            Assert.False(result.HasNextPage);
+        }
+
+        [Fact]
