public class InstructorsController : BaseController
{
    public InstructorsController(SchoolContext context) : base(context) {}

    public ActionResult Index(int? id, int? courseID)
    {
        var viewModel = new InstructorIndexData();
        viewModel.Instructors = db.Instructors
            .Include(i => i.OfficeAssignment)
            .Include(i => i.CourseAssignments).ThenInclude(c => c.Course).ThenInclude(d => d.Department)
            .OrderBy(i => i.LastName);

        if (id != null)
        {
            ViewBag.InstructorID = id.Value;
            viewModel.Courses = viewModel.Instructors.Where(i => i.ID == id.Value).Single().CourseAssignments.Select(s => s.Course);
        }
        if (courseID != null)
        {
            ViewBag.CourseID = courseID.Value;
            viewModel.Enrollments = viewModel.Courses.Where(x => x.CourseID == courseID).Single().Enrollments;
        }
        return View(viewModel);
    }

    public ActionResult Details(int? id)
    {
        if (id == null) return new StatusCodeResult(400);
        Instructor instructor = db.Instructors.Find(id);
        if (instructor == null) return NotFound();
        return View(instructor);
    }

    public ActionResult Create()
    {
        var instructor = new Instructor();
        instructor.CourseAssignments = new List<CourseAssignment>();
        PopulateAssignedCourseData(instructor);
        return View(instructor);
    }

    [HttpPost] [ValidateAntiForgeryToken]
    public ActionResult Create([Bind(...)] Instructor instructor, string[] selectedCourses)
    {
        if (selectedCourses != null)
        {
            instructor.CourseAssignments = new List<CourseAssignment>();
            foreach (var course in selectedCourses)
            {
                var courseToAdd = new CourseAssignment { InstructorID = instructor.ID, CourseID = int.Parse(course) };
                instructor.CourseAssignments.Add(courseToAdd);
            }
        }
        if (ModelState.IsValid)
        {
            db.Instructors.Add(instructor);
            db.SaveChanges();
            SendEntityNotification("Instructor", instructor.ID.ToString(), EntityOperation.CREATE);
            return RedirectToAction("Index");
        }
        PopulateAssignedCourseData(instructor);
        return View(instructor);
    }

    public ActionResult Edit(int? id)
    {
        if (id == null) return new StatusCodeResult(400);
        Instructor instructor = db.Instructors.Include(i => i.OfficeAssignment)
            .Include(i => i.CourseAssignments).ThenInclude(c => c.Course)
            .Where(i => i.ID == id).Single();
        PopulateAssignedCourseData(instructor);
        if (instructor == null) return NotFound();
        return View(instructor);
    }

    private void PopulateAssignedCourseData(Instructor instructor)
    {
        var allCourses = db.Courses;
        var instructorCourses = new HashSet<int>(instructor.CourseAssignments.Select(c => c.CourseID));
        var viewModel = new List<AssignedCourseData>();
        foreach (var course in allCourses)
        {
            viewModel.Add(new AssignedCourseData { CourseID = course.CourseID, Title = course.Title, Assigned = instructorCourses.Contains(course.CourseID) });
        }
        ViewBag.Courses = viewModel;
    }

    [HttpPost] [ValidateAntiForgeryToken]
    public async Task<ActionResult> Edit(int? id, string[] selectedCourses)
    {
        // Uses TryUpdateModelAsync - hard to unit test, so we can skip or test minimally
        // ...
    }

    public ActionResult Delete(int? id)
    {
        if (id == null) return new StatusCodeResult(400);
        Instructor instructor = db.Instructors.Find(id);
        if (instructor == null) return NotFound();
        return View(instructor);
    }

    [HttpPost, ActionName("Delete")] [ValidateAntiForgeryToken]
    public ActionResult DeleteConfirmed(int id)
    {
        Instructor instructor = db.Instructors.Include(i => i.OfficeAssignment).Where(i => i.ID == id).Single();
        db.Instructors.Remove(instructor);
        var department = db.Departments.Where(d => d.InstructorID == id).SingleOrDefault();
        if (department != null) department.InstructorID = null;
        db.SaveChanges();
        SendEntityNotification("Instructor", id.ToString(), EntityOperation.DELETE);
        return RedirectToAction("Index");
    }
}
