public class NotificationsController : BaseController
{
    public NotificationsController(SchoolContext context) : base(context) { }

    [HttpGet]
    public JsonResult GetNotifications()
    {
        var notifications = new List<Notification>();
        try
        {
            Notification notification;
            while ((notification = notificationService.ReceiveNotification()) != null)
            {
                notifications.Add(notification);
                if (notifications.Count >= 10) break;
            }
        }
        catch (Exception ex)
        {
            return Json(new { success = false, message = "Error retrieving notifications" });
        }
        return Json(new { success = true, notifications, count = notifications.Count });
    }

    [HttpPost]
    public JsonResult MarkAsRead(int id)
    {
        try
        {
            notificationService.MarkAsRead(id);
            return Json(new { success = true });
        }
        catch (Exception ex)
        {
            return Json(new { success = false, message = "Error updating notification" });
        }
    }

    public ActionResult Index() { return View(); }
}
```

Note: The notificationService is a field from BaseController (`protected NotificationService notificationService = new NotificationService();`). It uses a static ConcurrentQueue internally.

Tests:
- GetNotifications_NoNotifications_ReturnsEmptyList
- GetNotifications_WithNotifications_ReturnsNotifications (enqueue first via notificationService.SendNotification)
- GetNotifications_LimitsTo10Notifications
- MarkAsRead_ReturnsSuccess
- Index_ReturnsViewResult

When testing GetNotifications, first drain any existing notifications from the static queue, then enqueue specific notifications using `controller's notificationService` (accessible via reflection or just send notifications directly through a new NotificationService instance since the queue is static).

Actually since NotificationService uses a static queue, you can simply create a NotificationService, call SendNotification, then call controller.GetNotifications(). But be careful about test isolation — drain the queue in setup.

To drain: keep calling `new NotificationService().ReceiveNotification()` until null.

