using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : ControllerTestBase
    {
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _controller = new InstructorsController(Context);
            SetupControllerContext(_controller);
        }

        [Fact]
        public void Index_NoSelection_ReturnsViewWithAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(2, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Equal(2, model.Courses.Count());
            Assert.Contains(model.Courses, c => c.Title == "Calculus");
            Assert.Contains(model.Courses, c => c.Title == "Trigonometry");
        }

        [Fact]
        public void Index_WithInstructorIdAndCourseId_PopulatesEnrollments()
        {
            var result = _controller.Index(1, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Equal(2, model.Enrollments.Count());
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kim", instructor.LastName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithCoursesInViewBag()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            Assert.Equal(3, courses.Count);
        }

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_AddsInstructorToDb()
        {
            var instructor = new Instructor
            {
                LastName = "Jones",
                FirstMidName = "Jane",
                HireDate = new DateTime(2021, 6, 1)
            };

            _controller.Create(instructor, null);

            Assert.True(Context.Instructors.Any(i => i.LastName == "Jones"));
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "Brown",
                FirstMidName = "Alice",
                HireDate = new DateTime(2022, 1, 1)
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = Context.Instructors.First(i => i.LastName == "Brown");
            var assignments = Context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "NoLast",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kim", instructor.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kim", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(Context.Instructors.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            _controller.DeleteConfirmed(1);

            var dept = Context.Departments.First(d => d.DepartmentID == 1);
            Assert.Null(dept.InstructorID);
        }
    }
}

using System.Collections.Generic;
using System.Dynamic;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Newtonsoft.Json;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : ControllerTestBase
    {
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _controller = new NotificationsController(Context);
            SetupControllerContext(_controller);
            _notificationService = new NotificationService();

            // Drain the static queue for test isolation
            while (_notificationService.ReceiveNotification() != null) { }
        }

        [Fact]
        public void GetNotifications_NoNotifications_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = SerializeResult(result);
            Assert.True(json.success);
            Assert.Equal(0, (int)json.count);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            _notificationService.SendNotification("Student", "3", EntityOperation.CREATE);
            _notificationService.SendNotification("Course", "1050", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            var json = SerializeResult(result);
            Assert.True(json.success);
            Assert.Equal(2, (int)json.count);
        }

        [Fact]
        public void GetNotifications_LimitsTo10Notifications()
        {
            for (int i = 0; i < 15; i++)
            {
                _notificationService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            var json = SerializeResult(result);
            Assert.True(json.success);
            Assert.Equal(10, (int)json.count);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var json = SerializeResult(result);
            Assert.True(json.success);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        private static dynamic SerializeResult(JsonResult result)
        {
            var serialized = JsonConvert.SerializeObject(result.Value);
            return JsonConvert.DeserializeObject<ExpandoObject>(serialized);
        }
    }
}

