using ContosoUniversity.Controllers;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : ControllerTestBase
    {
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _controller = new HomeController(Context);
            SetupControllerContext(_controller);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResult()
        {
            var result = _controller.About();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsEnrollmentDateGroups()
        {
            var result = _controller.About() as ViewResult;

            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Seeded data has 3 students with different enrollment dates
            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.Equal(Context.Students.Count(), totalStudents);
        }

        [Fact]
        public void About_EachGroupHasEnrollmentDate()
        {
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            Assert.All(model, g => Assert.NotNull(g.EnrollmentDate));
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Contact_SetsViewBagMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_SetsViewBagMessage()
        {
            _controller.Unauthorized();

            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : ControllerTestBase
    {
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _controller = new StudentsController(Context);
            SetupControllerContext(_controller);
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsStudentsAsPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsType<PaginatedList<Student>>(result.Model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var lastNames = model.Select(s => s.LastName).ToList();
            Assert.Equal(lastNames.OrderBy(n => n), lastNames);
