using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : ControllerTestBase
    {
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _controller = new StudentsController(Context);
            SetupControllerContext(_controller);
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsStudentsAsPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsType<PaginatedList<Student>>(result.Model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var lastNames = model.Select(s => s.LastName).ToList();
            Assert.Equal(lastNames.OrderBy(n => n), lastNames);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var lastNames = model.Select(s => s.LastName).ToList();
            Assert.Equal(lastNames.OrderByDescending(n => n), lastNames);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d), dates);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchNoMatch_ReturnsEmpty()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Empty(model);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "Alexander", 5) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_WhenSortIsNameDesc_SetsNameSortParmToEmpty()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBagDateSortParm()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WhenSortIsDate_SetsDateSortParmToDateDesc()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_SetsViewBagCurrentFilter()
        {
            _controller.Index(null, null, "test", null);

            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        // --- Details Tests ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(3) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollments()
        {
            var result = _controller.Details(3) as ViewResult;
            var student = result.Model as Student;

            Assert.NotNull(student.Enrollments);
            Assert.NotEmpty(student.Enrollments);
        }

        [Fact]
        public void Details_ValidId_IncludesCourseInEnrollments()
        {
            var result = _controller.Details(3) as ViewResult;
            var student = result.Model as Student;

            Assert.All(student.Enrollments, e => Assert.NotNull(e.Course));
        }

        // --- Create GET Tests ---

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var result = _controller.Create();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsStudentWithTodaysDate()
        {
            var result = _controller.Create() as ViewResult;
            var student = Assert.IsType<Student>(result.Model);

            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        // --- Create POST Tests ---

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_AddsStudentToDb()
        {
            var initialCount = Context.Students.Count();
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(initialCount + 1, Context.Students.Count());
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = default(DateTime)
            };

            var result = _controller.Create(student);

            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_OutOfRangeDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Edit GET Tests ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(3) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        // --- Edit POST Tests ---

        [Fact]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var student = Context.Students.Find(3);
            Context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editStudent = new Student
            {
                ID = 3,
                LastName = "AlexanderEdited",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };

            var result = _controller.Edit(editStudent);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 3,
                LastName = "",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 3,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);

            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_OutOfRangeDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 3,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Edit(student);

            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Delete GET Tests ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(3) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
        {
            var initialCount = Context.Students.Count();

            var result = _controller.DeleteConfirmed(3);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(initialCount - 1, Context.Students.Count());
        }

        [Fact]
        public void DeleteConfirmed_StudentRemovedFromDb()
        {
            _controller.DeleteConfirmed(3);

            Assert.Null(Context.Students.Find(3));
        }
    }
}

