using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : ControllerTestBase
    {
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _controller = new HomeController(Context);
            SetupControllerContext(_controller);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResult_WithListOfEnrollmentDateGroup()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<List<EnrollmentDateGroup>>(viewResult.Model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDateCorrectly()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<List<EnrollmentDateGroup>>(viewResult.Model);

            // Seed data has 3 students each with a unique enrollment date
            Assert.Equal(3, model.Count);
            Assert.All(model, g => Assert.Equal(1, g.StudentCount));
        }

        [Fact]
        public void Contact_ReturnsViewResult_WithViewBagMessage()
        {
            var result = _controller.Contact();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", viewResult.ViewData["Message"]);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult_WithViewBagMessage()
        {
            var result = _controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", viewResult.ViewData["Message"]);
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : ControllerTestBase
    {
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _controller = new StudentsController(Context);
            SetupControllerContext(_controller);
        }

        // ==================== Index Tests ====================

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.True(model.Count >= 2);
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(
                    string.Compare(model[i].LastName, model[i + 1].LastName, StringComparison.Ordinal) <= 0,
                    $"Expected '{model[i].LastName}' <= '{model[i + 1].LastName}'");
            }
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.True(model.Count >= 2);
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(
                    string.Compare(model[i].LastName, model[i + 1].LastName, StringComparison.Ordinal) >= 0,
                    $"Expected '{model[i].LastName}' >= '{model[i + 1].LastName}'");
            }
        }

        [Fact]
        public void Index_DateSort_OrdersByDateAsc()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.True(model.Count >= 2);
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(model[i].EnrollmentDate <= model[i + 1].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_DateDescSort_OrdersByDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.True(model.Count >= 2);
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(model[i].EnrollmentDate >= model[i + 1].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            // "Alexander" is one of the seed students
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            // "Carson" is Alexander's first name
            var result = _controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            // Pass a page > 1 along with a new search string; page should reset to 1
            var result = _controller.Index(null, null, "A", 5);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Null(viewResult.ViewData["CurrentSort"]);
            Assert.Equal("name_desc", viewResult.ViewData["NameSortParm"]);
