using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : ControllerTestBase
    {
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _controller = new HomeController(Context);
            SetupControllerContext(_controller);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResult_WithListOfEnrollmentDateGroup()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<List<EnrollmentDateGroup>>(viewResult.Model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDateCorrectly()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<List<EnrollmentDateGroup>>(viewResult.Model);

            // Seed data has 3 students each with a unique enrollment date
            Assert.Equal(3, model.Count);
            Assert.All(model, g => Assert.Equal(1, g.StudentCount));
            Assert.Equal(Context.Students.Count(), model.Sum(g => g.StudentCount));
        }

        [Fact]
        public void Contact_ReturnsViewResult_WithViewBagMessageSet()
        {
            var result = _controller.Contact();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", viewResult.ViewData["Message"]);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult_WithViewBagMessageSet()
        {
            var result = _controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", viewResult.ViewData["Message"]);
        }
    }
}

