using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : ControllerTestBase
    {
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _controller = new StudentsController(Context);
            SetupControllerContext(_controller);
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsStudentsAsPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsType<PaginatedList<Student>>(result.Model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var lastNames = model.Select(s => s.LastName).ToList();
            Assert.Equal(lastNames.OrderBy(n => n), lastNames);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var lastNames = model.Select(s => s.LastName).ToList();
            Assert.Equal(lastNames.OrderByDescending(n => n), lastNames);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d), dates);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchNoMatch_ReturnsEmpty()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Empty(model);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "Alexander", 5) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
