            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_OutOfRangeDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // ==================== Edit GET Tests ====================

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(3);

            var viewResult = Assert.IsType<ViewResult>(result);
            var student = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        // ==================== Edit POST Tests ====================

        [Fact]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var student = Context.Students.Find(3)!;
            Context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editStudent = new Student
            {
                ID = 3,
                LastName = "AlexanderEdited",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };

            var result = _controller.Edit(editStudent);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 3,
                FirstMidName = "Carson",
                LastName = "",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 3,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // ==================== Delete GET Tests ====================

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
