            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(3) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
        {
            var initialCount = Context.Students.Count();

            var result = _controller.DeleteConfirmed(3);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(initialCount - 1, Context.Students.Count());
        }

        [Fact]
        public void DeleteConfirmed_StudentRemovedFromDb()
        {
            _controller.DeleteConfirmed(3);

            Assert.Null(Context.Students.Find(3));
        }
    }
