HomeController source:
```csharp
public class HomeController : BaseController
{
    public HomeController(SchoolContext context) : base(context) { }
    public ActionResult Index() { return View(); }
    public ActionResult About()
    {
        IQueryable<EnrollmentDateGroup> data = 
            from student in db.Students
            group student by student.EnrollmentDate into dateGroup
            select new EnrollmentDateGroup()
            {
                EnrollmentDate = dateGroup.Key,
                StudentCount = dateGroup.Count()
            };
        return View(data.ToList());
    }
    public ActionResult Contact()
    {
        ViewBag.Message = "Your contact page.";
        return View();
    }
    public ActionResult Error() { return View(); }
    public new ActionResult Unauthorized()
    {
        ViewBag.Message = "You don't have permission to access this resource.";
        return View();
    }
}
```

Tests:
- Index returns ViewResult
- About returns ViewResult with list of EnrollmentDateGroup as model
- About groups students by enrollment date correctly
- Contact returns ViewResult with ViewBag.Message set
- Error returns ViewResult
- Unauthorized returns ViewResult with ViewBag.Message set

